const fs = require('fs');
const path = require('path');
const DATA_DIR = path.join(__dirname, '..', 'data', 'scrape');
const timestamp = new Date().toISOString();

function normalizeProduct(p) {
  const productId = String(p.productId || '').replace(/\D/g, '');
  if (!productId || productId.length < 5) return null;
  const price = typeof p.price === 'number' ? p.price : (p.price?.current ?? 0);
  const wasRaw = p.wasPrice ?? p.price?.was ?? null;
  const wasPrice = wasRaw && wasRaw > 0 && wasRaw !== price ? wasRaw : null;
  const savingsRaw = p.savings ?? p.price?.savings ?? null;
  const savings = savingsRaw && savingsRaw > 0 ? savingsRaw : null;
  const rating = typeof p.rating === 'number' ? p.rating : (p.rating?.average ?? 0);
  const reviewCount = p.reviewCount || p.rating?.count || 0;
  const energyRating = p.energyRating && p.energyRating !== '' && p.energyRating !== 'null' ? p.energyRating : null;
  let brand = p.brand || '';
  const fixes = {'lg':'LG','jbl':'JBL','jvc':'JVC','tcl':'TCL','bose':'Bose','sony':'Sony','samsung':'Samsung','hisense':'Hisense','sonos':'Sonos','panasonic':'Panasonic','beats':'Beats','apple':'Apple','amazon':'Amazon','sharp':'Sharp','philips':'Philips','toshiba':'Toshiba','denon':'Denon','marshall':'Marshall','soundcore':'Soundcore','skullcandy':'Skullcandy','jlab':'JLab','roku':'Roku','freesat':'Freesat','manhattan':'Manhattan','humax':'Humax','majority':'Majority','oakcastle':'Oakcastle','streetz':'Streetz','logik':'Logik','groov-e':'Groov-e','fresh n rebel':'Fresh N Rebel','lazerbuilt':'Lazerbuilt','daewoo':'Daewoo'};
  const bl = brand.toLowerCase();
  if (fixes[bl]) brand = fixes[bl];
  else brand = brand.charAt(0).toUpperCase() + brand.slice(1);
  return {productId,name:p.name||p.title||'',brand,url:(p.url||p.productUrl||'').replace('https://www.currys.co.uk',''),imageUrl:p.imageUrl||null,price:{current:price,was:wasPrice,savings},rating:{average:rating,count:reviewCount},specs:p.keySpecs||p.specs||[],badges:(p.badges||[]).filter(b=>!b.includes('Delivery')&&!b.includes('collection')),offers:(p.offers||[]).filter(o=>!o.includes('FREE in-store')),deliveryFree:true,energyRating,inStock:p.inStock!==false};
}

function mergeProducts(arrays) {
  const seen = new Map();
  for (const arr of arrays) {
    for (const p of arr) {
      const n = normalizeProduct(p);
      if (!n) continue;
      if (!seen.has(n.productId) || (n.specs.length > (seen.get(n.productId).specs?.length||0))) seen.set(n.productId, n);
    }
  }
  return Array.from(seen.values());
}

function loadExisting(file) {
  try { const d = JSON.parse(fs.readFileSync(path.join(DATA_DIR,file),'utf8')); return d.products||[]; } catch { return []; }
}

function buildFilters(products) {
  const f = [{name:'Hide out of stock',isExpanded:true,type:'toggle',options:[]}];
  const bc = {};
  products.forEach(p=>{if(p.brand)bc[p.brand]=(bc[p.brand]||0)+1;});
  f.push({name:'Brand',isExpanded:true,type:'checkbox',options:Object.entries(bc).sort((a,b)=>b[1]-a[1]).map(([l,c])=>({label:l,count:c}))});
  const pr = [{l:'Up to £100',a:0,b:100},{l:'£100 to £300',a:100,b:300},{l:'£300 to £500',a:300,b:500},{l:'£500 to £1,000',a:500,b:1000},{l:'£1,000 and above',a:1000,b:Infinity}];
  const po = pr.map(r=>({label:r.l,count:products.filter(p=>p.price.current>=r.a&&p.price.current<r.b).length})).filter(o=>o.count>0);
  if(po.length>0) f.push({name:'Price',isExpanded:true,type:'checkbox',options:po});
  const ro = [5,4,3].map(s=>({label:`${s} stars & above`,count:products.filter(p=>p.rating.average>=s).length})).filter(o=>o.count>0);
  if(ro.length>0) f.push({name:'Customer Rating',isExpanded:false,type:'rating',options:ro});
  return f;
}

function save(file, slug, name, url, products) {
  const out = {categoryName:name,categorySlug:slug,url,scrapedAt:timestamp,totalProducts:products.length,filters:buildFilters(products),products};
  fs.writeFileSync(path.join(DATA_DIR,file), JSON.stringify(out,null,2));
  console.log(`${file}: ${products.length} products`);
  return products.length;
}

