// Deduplication report
const allIds = new Set();
const catCounts = {};
const files = ['category-tvs.json','digital-smart-tv.json','dvd-blu-ray.json','soundbars.json','speakers-hifi.json','headphones.json','tv-accessories.json'];
let totalEntries = 0;
for (const f of files) {
  try {
    const d = JSON.parse(fs.readFileSync(path.join(DATA_DIR,f),'utf8'));
    const ids = (d.products||[]).map(p=>p.productId);
    catCounts[f] = ids.length;
    totalEntries += ids.length;
    ids.forEach(id => allIds.add(id));
  } catch {}
}

console.log('\n=== DEDUPLICATION REPORT ===');
console.log(`Total entries across 7 categories: ${totalEntries}`);
console.log(`Unique product IDs: ${allIds.size}`);
console.log(`Duplicates (across categories): ${totalEntries - allIds.size}`);
console.log('\nPer-category counts:');
for (const [f, c] of Object.entries(catCounts)) {
  console.log(`  ${f}: ${c} products`);
}

// Save product details for new products
let detailsSaved = 0;
for (const id of allIds) {
  const detailFile = path.join(PRODUCTS_DIR, `${id}.json`);
  if (!fs.existsSync(detailFile)) {
    // Find the product in any category
    for (const f of files) {
      try {
        const d = JSON.parse(fs.readFileSync(path.join(DATA_DIR,f),'utf8'));
        const p = (d.products||[]).find(p=>p.productId===id);
        if (p) {
          const detail = {productId:id,name:p.name,brand:p.brand,url:p.url,price:p.price,rating:p.rating,imageUrl:p.imageUrl,specs:p.specs||p.keySpecs||[],badges:p.badges||[],offers:p.offers||[],energyRating:p.energyRating,scrapedAt:timestamp,source:'listing-only'};
          fs.writeFileSync(detailFile, JSON.stringify(detail, null, 2));
          detailsSaved++;
          break;
        }
      } catch {}
    }
  }
}
console.log(`\nNew product detail files created: ${detailsSaved}`);
console.log(`Total product detail files: ${fs.readdirSync(PRODUCTS_DIR).filter(f=>f.endsWith('.json')).length}`);
